    18	func mergeDataTableSpecResults(sResult *result.SuiteResult) *result.SuiteResult {
    19		suiteRes := result.NewSuiteResult(sResult.Tags, time.Now())
    20		suiteRes.IsFailed = sResult.IsFailed
    21		suiteRes.ExecutionTime = sResult.ExecutionTime
    22		suiteRes.PostSuite = sResult.PostSuite
    23		suiteRes.PreSuite = sResult.PreSuite
    24		suiteRes.UnhandledErrors = sResult.UnhandledErrors
    25		suiteRes.Timestamp = sResult.Timestamp
    26		suiteRes.TimestampISO = sResult.TimestampISO
    27		suiteRes.ProjectName = sResult.ProjectName
    28		suiteRes.Environment = sResult.Environment
    29		suiteRes.Tags = sResult.Tags
    30		suiteRes.PreHookMessages = append(suiteRes.PreHookMessages, sResult.PreHookMessages...)
    31		suiteRes.PostHookMessages = append(suiteRes.PostHookMessages, sResult.PostHookMessages...)
    32		suiteRes.PreHookScreenshotFiles = append(suiteRes.PreHookScreenshotFiles, sResult.PreHookScreenshotFiles...)
    33		suiteRes.PostHookScreenshotFiles = append(suiteRes.PostHookScreenshotFiles, sResult.PostHookScreenshotFiles...)
    34		suiteRes.PreHookScreenshots = append(suiteRes.PreHookScreenshots, sResult.PreHookScreenshots...)
    35		suiteRes.PostHookScreenshots = append(suiteRes.PostHookScreenshots, sResult.PostHookScreenshots...)
    36		combinedResults := make(map[string][]*result.SpecResult)
    37		for _, res := range sResult.SpecResults {
    38			fileName := res.ProtoSpec.GetFileName()
    39			combinedResults[fileName] = append(combinedResults[fileName], res)
    40		}
    41		for _, res := range combinedResults {
    42			mergedRes := res[0]
    43			if len(res) > 1 {
    44				mergedRes = mergeResults(res)
    45			}
    46			if mergedRes.GetFailed() {
    47				suiteRes.SpecsFailedCount++
    48			} else if mergedRes.Skipped {
    49				suiteRes.SpecsSkippedCount++
    50			}
    51			suiteRes.SpecResults = append(suiteRes.SpecResults, mergedRes)
    52		}
    53		return suiteRes
    54	}
    55	
    56	func hasTableDrivenSpec(results []*result.SpecResult) bool {
    57		for _, r := range results {
    58			if r.ProtoSpec.GetIsTableDriven() {
    59				return true
    60			}
    61		}
    62		return false
    63	}
    64	
    65	func mergeResults(results []*result.SpecResult) *result.SpecResult {
    66		specResult := &result.SpecResult{ProtoSpec: &m.ProtoSpec{
    67			IsTableDriven:    hasTableDrivenSpec(results),
    68			PreHookMessages:  results[0].ProtoSpec.PreHookMessages,
    69			PostHookMessages: results[len(results)-1].ProtoSpec.PostHookMessages,
    70		}}
    71		var scnResults []*m.ProtoItem
    72		table := &m.ProtoTable{}
    73		dataTableScnResults := make(map[string][]*m.ProtoTableDrivenScenario)
    74		includedTableRowIndexMap := make(map[int32]bool)
    75		max := results[0].ExecutionTime
    76		for _, res := range results {
    77			specResult.ExecutionTime += res.ExecutionTime
    78			specResult.Errors = res.Errors
    79			if res.ExecutionTime > max {
    80				max = res.ExecutionTime
    81			}
    82			if res.GetFailed() {
    83				specResult.IsFailed = true
    84			}
    85	
    86			var tableRows []*m.ProtoTableRow // nolint
    87	
    88			for _, item := range res.ProtoSpec.Items {
    89				switch item.ItemType {
    90				case m.ProtoItem_Scenario:
    91					scnResults = append(scnResults, item)
    92					modifySpecStats(item.Scenario, specResult)
    93				case m.ProtoItem_TableDrivenScenario:
    94					tableRowIndex := item.TableDrivenScenario.TableRowIndex
    95					if _, ok := includedTableRowIndexMap[tableRowIndex]; !ok {
    96						table.Rows = append(table.Rows, tableRows...)
    97						includedTableRowIndexMap[tableRowIndex] = true
    98					}
    99					item.TableDrivenScenario.TableRowIndex = int32(len(table.Rows) - 1)
   100					scnResults = append(scnResults, item)
   101					heading := item.TableDrivenScenario.Scenario.ScenarioHeading
   102					dataTableScnResults[heading] = append(dataTableScnResults[heading], item.TableDrivenScenario)
   103				case m.ProtoItem_Table:
   104					table.Headers = item.Table.Headers
   105					tableRows = item.Table.GetRows()
   106					if len(res.GetPreHook()) > 0 {
   107						table.Rows = append(table.Rows, tableRows...)
   108					}
   109				}
   110			}
   111			addHookFailure(table, res.GetPreHook(), specResult.AddPreHook)
   112			addHookFailure(table, res.GetPostHook(), specResult.AddPostHook)
   113		}
   114		if InParallel {
   115			specResult.ExecutionTime = max
   116		}
   117		aggregateDataTableScnStats(dataTableScnResults, specResult)
   118		specResult.ProtoSpec.FileName = results[0].ProtoSpec.FileName
   119		specResult.ProtoSpec.Tags = results[0].ProtoSpec.Tags
   120		specResult.ProtoSpec.SpecHeading = results[0].ProtoSpec.SpecHeading
   121		specResult.ProtoSpec.Items = getItems(table, scnResults, results)
   122		return specResult
   123	}
   124	
   125	func addHookFailure(table *m.ProtoTable, f []*m.ProtoHookFailure, add func(...*m.ProtoHookFailure)) {
   126		for _, h := range f {
   127			h.TableRowIndex = int32(len(table.Rows) - 1)
   128		}
   129		add(f...)
   130	}
   131	
   132	func getItems(table *m.ProtoTable, scnResults []*m.ProtoItem, results []*result.SpecResult) (items []*m.ProtoItem) {
   133		index := 0
   134		for _, item := range results[0].ProtoSpec.Items {
   135			switch item.ItemType {
   136			case m.ProtoItem_Scenario, m.ProtoItem_TableDrivenScenario:
   137				items = append(items, scnResults[index])
   138				index++
   139			case m.ProtoItem_Table:
   140				items = append(items, &m.ProtoItem{ItemType: m.ProtoItem_Table, Table: table})
   141			default:
   142				items = append(items, item)
   143			}
   144		}
   145		items = append(items, scnResults[index:]...)
   146		return
   147	}
   148	
   149	func aggregateDataTableScnStats(results map[string][]*m.ProtoTableDrivenScenario, specResult *result.SpecResult) {
   150		for _, dResult := range results {
   151			for _, res := range dResult {
   152				isTableIndicesExcluded := false
   153				if res.Scenario.ExecutionStatus == m.ExecutionStatus_FAILED {
   154					specResult.ScenarioFailedCount++
   155				} else if res.Scenario.ExecutionStatus == m.ExecutionStatus_SKIPPED &&
   156					!strings.Contains(res.Scenario.SkipErrors[0], "--table-rows") {
   157					specResult.ScenarioSkippedCount++
   158					specResult.Skipped = true
   159				} else if res.Scenario.ExecutionStatus == m.ExecutionStatus_SKIPPED &&
   160					strings.Contains(res.Scenario.SkipErrors[0], "--table-rows") {
   161					isTableIndicesExcluded = true
   162				}
   163				if !isTableIndicesExcluded {
   164					specResult.ScenarioCount++
   165				}
   166			}
   167		}
   168	}
   169	
   170	func modifySpecStats(scn *m.ProtoScenario, specRes *result.SpecResult) {
   171		switch scn.ExecutionStatus {
   172		case m.ExecutionStatus_SKIPPED:
   173			specRes.ScenarioSkippedCount++
   174		case m.ExecutionStatus_FAILED:
   175			specRes.ScenarioFailedCount++
   176		}
   177		specRes.ScenarioCount++
   178	}
